// And groups predicates with the AND operator between them.
func And(predicates ...predicate.OAuthAuthorisationCode) predicate.OAuthAuthorisationCode {
	return predicate.OAuthAuthorisationCode(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.OAuthAuthorisationCode) predicate.OAuthAuthorisationCode {
	return predicate.OAuthAuthorisationCode(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.OAuthAuthorisationCode) predicate.OAuthAuthorisationCode {
	return predicate.OAuthAuthorisationCode(sql.NotPredicates(p))
}
